function dt(s){return new Date(s+"T00:00:00");}
function SS(ini,fin,av){
  var f=dt(fin),i=dt(ini);
  if(av>=100)return "done";
  if(TODAY<i)return "pend";
  if(TODAY>f)return "late";
  var el=(TODAY-i)/(f-i),exp=Math.round(Math.min(100,el*100));
  if(av>=exp)return "ok";
  if(av>=exp*0.65)return "risk";
  return "late";
}
function GR2(d,cl,b,pk){
  if(!LD2.filas)return [];
  return LD2.filas.filter(function(r){return r["Distrito"]===d&&r["Cluster"]===cl&&r["Bodega"]===b&&(r["Proceso"]||"").indexOf(pk)>=0;});
}
function PA(d,cl,b,pi){
  var rows=GR2(d,cl,b,PK[pi]);
  if(!rows.length)return 0;
  var s=0;
  rows.forEach(function(r){s+=parseFloat(r["% Avance"]||0);});
  return Math.round(s/rows.length);
}
function WP(d,cl,b){return Math.round((PA(d,cl,b,0)+PA(d,cl,b,1)+PA(d,cl,b,2))/3);}
function CP(d,cl){var bs=DB[d][cl];return Math.round(bs.reduce(function(s,b){return s+WP(d,cl,b);},0)/bs.length);}
function DP(d){var cls=Object.keys(DB[d]);return Math.round(cls.reduce(function(s,cl){return s+CP(d,cl);},0)/cls.length);}
function TP(){return Math.round((DP("Distrito A")*36+DP("Distrito B")*20)/56);}
function CD2(){
  var n=0;
  ["Distrito A","Distrito B"].forEach(function(d){Object.keys(DB[d]).forEach(function(cl){DB[d][cl].forEach(function(b){if(WP(d,cl,b)===100)n++;});});});
  return n;
}
function CL(){
  var n=0;
  if(!LD2.filas)return 0;
  LD2.filas.forEach(function(r){var av=parseFloat(r["% Avance"]||0),ini=r["Inicio Proyectado"]||"",fin=r["Fin Proyectado"]||"";if(ini&&fin&&SS(ini,fin,av)==="late")n++;});
  return n;
}
function WS(d,cl,b){
  var late=0,risk=0,ok=0;
  if(!LD2.filas)return "pend";
  LD2.filas.filter(function(r){return r["Distrito"]===d&&r["Cluster"]===cl&&r["Bodega"]===b;}).forEach(function(r){
    var av=parseFloat(r["% Avance"]||0),ini=r["Inicio Proyectado"]||"",fin=r["Fin Proyectado"]||"";
    if(!ini||!fin)return;
    var s=SS(ini,fin,av);
    if(s==="late")late++;else if(s==="risk")risk++;else if(s==="ok"||s==="done")ok++;
  });
  if(late>0)return "late";if(risk>0)return "risk";if(ok>0)return "ok";return "pend";
}
